class Solution:
    def equalSubstring(self, s, t, maxCost):
        n = len(s)
        cost = [abs(ord(s[i]) - ord(t[i])) for i in range(n)]
        best = 0
        for i in range(n):
            run = 0
            for j in range(i, n):
                run += cost[j]
                if run > maxCost:
                    break
                best = max(best, j - i + 1)
        return best

