class Solution:
    def equalSubstring(self, s, t, maxCost):
        n = len(s)
        left = 0
        run = 0
        best = 0
        for right in range(n):
            run += abs(ord(s[right]) - ord(t[right]))
            while run > maxCost:
                run -= abs(ord(s[left]) - ord(t[left]))
                left += 1
            best = max(best, right - left + 1)
        return best

