var equalSubstring = function(s, t, maxCost) {
    const n = s.length;
    let left = 0, run = 0, best = 0;
    for (let right = 0; right < n; right++) {
        run += Math.abs(s.charCodeAt(right) - t.charCodeAt(right));
        while (run > maxCost) {
            run -= Math.abs(s.charCodeAt(left) - t.charCodeAt(left));
            left++;
        }
        best = Math.max(best, right - left + 1);
    }
    return best;
};
